// ============================================
// 進階功率分析模組 (整合 GoldenCheetah + cycling-analytics)
// ============================================

const CTL_TIME_CONSTANT = 42;
const ATL_TIME_CONSTANT = 7;
const NP_WINDOW_SIZE = 30;
const MMP_DURATIONS = [1, 5, 10, 15, 20, 30, 45, 60, 90, 120, 180, 240, 300, 360, 480, 600, 720, 900, 1200, 1800, 2400, 3600, 5400, 7200];

const POWER_ZONES = [
  { zone: 1, name: '主動恢復', minPct: 0, maxPct: 0.55 },
  { zone: 2, name: '耐力', minPct: 0.56, maxPct: 0.75 },
  { zone: 3, name: '節奏', minPct: 0.76, maxPct: 0.90 },
  { zone: 4, name: '乳酸閾值', minPct: 0.91, maxPct: 1.05 },
  { zone: 5, name: 'VO2max', minPct: 1.06, maxPct: 1.20 },
  { zone: 6, name: '無氧', minPct: 1.21, maxPct: 1.50 },
  { zone: 7, name: '神經肌肉', minPct: 1.51, maxPct: 999 },
];

// Normalized Power 計算
function calculateNP(powerData) {
  if (!powerData || powerData.length < 30) {
    return powerData?.length > 0 ? Math.round(powerData.reduce((a, b) => a + b, 0) / powerData.length) : 0;
  }
  const rollingAvg = [];
  for (let i = 29; i < powerData.length; i++) {
    let sum = 0;
    for (let j = i - 29; j <= i; j++) sum += powerData[j];
    rollingAvg.push(sum / 30);
  }
  const sumFourthPower = rollingAvg.reduce((sum, val) => sum + Math.pow(val, 4), 0);
  return Math.round(Math.pow(sumFourthPower / rollingAvg.length, 0.25));
}

// TSS 計算
function calculateTSS(np, ftp, duration) {
  if (ftp <= 0 || np <= 0) return 0;
  const intensityFactor = np / ftp;
  return Math.round((duration * np * intensityFactor) / (ftp * 3600) * 1000) / 10;
}

// 指數衰減 CTL/ATL
function calcExpCTL(prev, tss) { return (1 - 1 / CTL_TIME_CONSTANT) * prev + (1 / CTL_TIME_CONSTANT) * tss; }
function calcExpATL(prev, tss) { return (1 - 1 / ATL_TIME_CONSTANT) * prev + (1 / ATL_TIME_CONSTANT) * tss; }

// MMP 計算
function calculateMMP(powerData, duration) {
  if (!powerData || powerData.length < duration) return 0;
  let maxAvg = 0, windowSum = 0;
  for (let i = 0; i < duration; i++) windowSum += powerData[i];
  maxAvg = windowSum / duration;
  for (let i = duration; i < powerData.length; i++) {
    windowSum = windowSum - powerData[i - duration] + powerData[i];
    const avg = windowSum / duration;
    if (avg > maxAvg) maxAvg = avg;
  }
  return Math.round(maxAvg);
}

function calculateFullMMP(powerData) {
  const mmp = {};
  for (const d of MMP_DURATIONS) {
    if (d <= powerData.length) mmp[d] = calculateMMP(powerData, d);
  }
  return mmp;
}

// Morton's 3P CP 模型
function fitMorton3P(pdCurve) {
  if (!pdCurve || pdCurve.length < 3) return { cp: 0, wPrime: 0, tau: 20, pMax: 0, r2: 0 };
  const validPoints = pdCurve.filter(p => p.power > 0 && p.duration > 5);
  if (validPoints.length < 3) return { cp: 0, wPrime: 0, tau: 20, pMax: 0, r2: 0 };

  let cp = validPoints[validPoints.length - 1].power;
  let wPrime = 20000, tau = 15;

  for (let iter = 0; iter < 200; iter++) {
    let gradCP = 0, gradWPrime = 0, gradTau = 0;
    for (const point of validPoints) {
      const denom = Math.max(point.duration - tau, 0.1);
      const pPred = cp + wPrime / denom;
      const err = point.power - pPred;
      gradCP -= 2 * err;
      gradWPrime -= 2 * err / denom;
      gradTau -= 2 * err * wPrime / (denom * denom);
    }
    cp -= 0.001 * gradCP;
    wPrime -= 0.001 * gradWPrime * 1000;
    tau -= 0.001 * gradTau * 10;
    cp = Math.max(100, Math.min(600, cp));
    wPrime = Math.max(5000, Math.min(60000, wPrime));
    tau = Math.max(5, Math.min(40, tau));
  }

  const meanP = validPoints.reduce((s, p) => s + p.power, 0) / validPoints.length;
  let ssTotal = 0, ssRes = 0;
  for (const point of validPoints) {
    ssTotal += Math.pow(point.power - meanP, 2);
    ssRes += Math.pow(point.power - (cp + wPrime / Math.max(point.duration - tau, 0.1)), 2);
  }
  const r2 = 1 - ssRes / ssTotal;
  return { cp: Math.round(cp), wPrime: Math.round(wPrime), wPrimeKJ: Math.round(wPrime / 100) / 10, tau: Math.round(tau * 10) / 10, pMax: Math.round(cp + wPrime / tau), r2: Math.round(r2 * 1000) / 1000 };
}

function extractPowerData(streams) {
  if (!streams) return [];
  if (typeof streams === 'string') {
    try { streams = JSON.parse(streams); } catch { return []; }
  }
  if (!Array.isArray(streams)) return [];
  const wattsStream = streams.find(s => s.type === 'watts');
  return wattsStream?.data || [];
}

// === 主邏輯 ===
const items = $input.all();
const first = items[0]?.json || {};
const ftp = first.athlete_ftp || 200;
const maxHR = first.athlete_max_hr || 185;

const activities = [], dailyTSS = {}, allMMP = {};
let ctl = 0, atl = 0, totalDuration = 0, totalDistance = 0, totalElevation = 0;

for (const item of items) {
  const json = item.json;
  const powerData = extractPowerData(json.streams);
  if (powerData.length === 0) continue;

  const np = calculateNP(powerData);
  const duration = json.moving_time || powerData.length;
  const tss = calculateTSS(np, ftp, duration);
  const dateKey = new Date(json.start_date || json.created_at).toISOString().split('T')[0];

  dailyTSS[dateKey] = (dailyTSS[dateKey] || 0) + tss;
  totalDuration += duration;
  totalDistance += json.distance || 0;
  totalElevation += json.total_elevation_gain || 0;

  // MMP
  const mmp = calculateFullMMP(powerData);
  for (const [d, p] of Object.entries(mmp)) {
    if (!allMMP[d] || p > allMMP[d]) allMMP[d] = p;
  }

  activities.push({ id: json.activity_id, date: dateKey, np, tss, avgPower: Math.round(powerData.reduce((a, b) => a + b, 0) / powerData.length) });
}

// 計算 CTL/ATL
const sortedDates = Object.keys(dailyTSS).sort();
for (const date of sortedDates) {
  ctl = calcExpCTL(ctl, dailyTSS[date]);
  atl = calcExpATL(atl, dailyTSS[date]);
}
const tsb = Math.round(ctl - atl);

// CP 模型
const pdCurve = Object.entries(allMMP).map(([d, p]) => ({ duration: parseInt(d), power: p }));
const cpModel = fitMorton3P(pdCurve);

// FTP 預測
const ftpEstimates = {};
if (allMMP[1200]) ftpEstimates.from20min = Math.round(allMMP[1200] * 0.95);
if (allMMP[3600]) ftpEstimates.from60min = allMMP[3600];
if (cpModel.cp > 0) ftpEstimates.fromCP = cpModel.cp;
const estimates = Object.values(ftpEstimates);
const predictedFTP = estimates.length > 0 ? Math.round(estimates.reduce((a, b) => a + b, 0) / estimates.length) : ftp;

return [{
  json: {
    athlete: { name: `${first.firstname || ''} ${first.lastname || ''}`.trim() || '選手', ftp, maxHR },
    period: { startDate: new Date(Date.now() - 42 * 86400000).toISOString().split('T')[0], endDate: new Date().toISOString().split('T')[0], totalDays: 42 },
    summary: { totalActivities: activities.length, totalTSS: Math.round(Object.values(dailyTSS).reduce((a, b) => a + b, 0)), ctl: Math.round(ctl), atl: Math.round(atl), tsb, totalHours: Math.round(totalDuration / 360) / 10, totalDistance: Math.round(totalDistance / 1000), totalElevation: Math.round(totalElevation) },
    cpModel,
    ftpPrediction: { currentFTP: ftp, predictedFTP, estimates: ftpEstimates, confidence: cpModel.r2 > 0.95 ? 'high' : cpModel.r2 > 0.85 ? 'medium' : 'low', recommendation: predictedFTP > ftp * 1.05 ? `建議更新 FTP 至 ${predictedFTP}W (+${Math.round((predictedFTP / ftp - 1) * 100)}%)` : predictedFTP < ftp * 0.95 ? 'FTP 可能下降，建議重新測試' : '當前 FTP 設定合理' },
    mmpCurve: { '5s': allMMP[5] || 0, '30s': allMMP[30] || 0, '1min': allMMP[60] || 0, '5min': allMMP[300] || 0, '20min': allMMP[1200] || 0, '60min': allMMP[3600] || 0 },
    highlights: activities.sort((a, b) => b.tss - a.tss).slice(0, 3),
    notificationType: $('Webhook 觸發').item?.json?.notification_type || 'line',
  }
}];

